#nullable enable // autogenerated

using System;
using System.Collections.Generic;
using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.language)]
    public class LanguageOptionDropdown : OptionDropdownDefinition
    {
        public LanguageOptionDropdown(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            if (context is IOptionContextLevel level)
            {
                return false;
            }
            return true;
        }
        public override int GetValue(IOptionContext context)
        {
            var codes = Global.Localization.GetAllLanguageCodes();
            var lang = context.TryGetCachedOptionString(LogicOptionItemID.language, out var value) ? value : Global.Localization.GetCurrentLanguage();
            var index = Array.IndexOf(codes, lang);
            if (index < 0)
                index = 0;
            return index;
        }
        public override void FillItems(IOptionContext context, List<string> items)
        {
            var codes = Global.Localization.GetAllLanguageCodes();
            foreach (var code in codes)
            {
                var label = Global.Localization.GetLanguageName(code);
                items.Add(label);
            }
        }
        public override void OnValueChanged(IOptionContext context, int index)
        {
            var codes = Global.Localization.GetAllLanguageCodes();
            context.CacheOptionString(LogicOptionItemID.language, codes[index]);
            context.SetNeedReload();
        }
    }
}
